逐步分析这段代码public byte[] sm4Encrypt(byte[] input, byte[] key) {
        byte[] output = new byte[input.length];
        int[] rk = sm4KeyExpansion(key);
        sm4Crypt(input, output, rk);
        return output;
    }

    public byte[] sm4Decrypt(byte[] input, byte[] key) {
        byte[] output = new byte[input.length];
        int[] rk = sm4KeyExpansion(key);
        sm4Crypt(input, output, Arrays.copyOfRange(rk, 0, 32));
        return output;
    }

逐步分析这段代码private static int sm4Lt(int ka) {
        int bb = 0;
        int c = 0;
        bb = sm4Sbox(ka & 0xFF);
        bb |= sm4Sbox((ka >> 8) & 0xFF) << 8;
        bb |= sm4Sbox((ka >> 16) & 0xFF) << 16;
        bb |= sm4Sbox((ka >> 24) & 0xFF) << 24;
        c = bb ^ rotl(bb, 2) ^ rotl(bb, 10) ^ rotl(bb, 18) ^ rotl(bb, 24);
        return c;
    }

